previewCss:
.darma-loader-darma-custom-310 {
  color: var(--loader-color, #4f46e5);
  height: 54px;
  aspect-ratio: 2;
  border-bottom: 3px solid #0000;
  background: 
    linear-gradient(90deg,var(--loader-secondary-color, #a5b4fc) 50%,#0000 0)
    -25% 100%/50% 3px repeat-x border-box;
  position: relative;
  animation: darma-loader-darma-custom-310-l3-0 .75s linear infinite;
}
.darma-loader-darma-custom-310:before {
  content: "";
  position: absolute;
  inset: auto 42.5% 0;
  aspect-ratio: 1;
  border-radius: 50%;
  background: var(--loader-color, #4f46e5);
  animation: darma-loader-darma-custom-310-l3-1 .75s cubic-bezier(0,900,1,900) infinite;
}
@keyframes darma-loader-darma-custom-310-l3-0 {
  to {background-position: -125% 100%}
}
@keyframes darma-loader-darma-custom-310-l3-1 {
  0%,2% {bottom: 0%}
  98%,to {bottom:.1%}
}

